class Solution {
public:
    int largestInteger(int num) {
        string str = to_string(num);
        vector<int> odd, even;
        for (char c : str) {
            int digit = c - '0';
            if (digit % 2 == 0) even.push_back(digit);
            else odd.push_back(digit);
        }
        sort(odd.rbegin(), odd.rend());
        sort(even.rbegin(), even.rend());
        int o = 0, e = 0;
        for (int i = 0; i < str.size(); i++) {
            int digit = str[i] - '0';
            if (digit % 2 == 0) {
                str[i] = '0' + even[e++];
            } else {
                str[i] = '0' + odd[o++];
            }
        }
        return stoi(str);
    }
};
efficiency: HIGH
time complexity: O(n log n)
space complexity: O(n)
energy implications: LOW
explanation: The solution converts the number to a string, separates the digits into two vectors based on parity, sorts them in descending order, and then reconstructs the number with the largest possible digits of the same parity in each position.
